#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[100005];
    while (T--) {
        scanf("%s", s);
        long long n = strlen(s);
        long long total = 0;
        for (long long i = 0; i < n; ++i) {
            for (long long j = i; j < n; ++j) {
                long long count4 = 0, count7 = 0;
                for (long long k = i; k <= j; ++k) {
                    if (s[k] == '4') ++count4;
                    else ++count7;
                }
                bool found = false;
                for (long long k = i; k <= j; ++k) {
                    long long left4 = 0, right7 = 0;
                    for (long long l = i; l < k; ++l) {
                        if (s[l] == '4') ++left4;
                    }
                    for (long long l = k; l <= j; ++l) {
                        if (s[l] == '7') ++right7;
                    }
                    if (left4 == right7) {
                        found = true;
                        break;
                    }
                }
                if (found) ++total;
            }
        }
        printf("%lld\n", total);
    }
    return 0;
}

