#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        s = data[idx]
        idx += 1
        n = len(s)
        total = 0
        for i in range(n):
            for j in range(i, n):
                count4 = 0
                count7 = 0
                for k in range(i, j+1):
                    if s[k] == '4':
                        count4 += 1
                    else:
                        count7 += 1
                found = False
                for k in range(i, j+1):
                    left4 = 0
                    right7 = 0
                    for l in range(i, k):
                        if s[l] == '4':
                            left4 += 1
                    for l in range(k, j+1):
                        if s[l] == '7':
                            right7 += 1
                    if left4 == right7:
                        found = True
                        break
                if found:
                    total += 1
        out_lines.append(str(total))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

